const input = $input.item.json;
let { inputType, inputText, inputFileId, inputLocation, metadata } = input;

if (inputType === 'text') {
  return [{ json: input }];
}

if (inputType === 'voice' && inputFileId) {
  try {
    const jarvisLog = (lvl, msg, meta = {}) => {
      const lvls = { debug: 0, info: 1, warn: 2, error: 3 };
      if (lvls[lvl] >= (lvls[($env.LOG_LEVEL || 'info').toLowerCase()] ?? 1)) {
        const wf = 'input-processor';
        console[lvl === 'error' ? 'error' : lvl === 'warn' ? 'warn' : 'log'](JSON.stringify({ timestamp: new Date().toISOString(), level: lvl, traceId: input.sessionId || 'unknown', workflow: wf, message: msg, meta }));
      }
    };
    jarvisLog('info', 'Transcribing voice message', { fileId: inputFileId });

    const fileRes = await $helpers.httpRequest({
      method: 'GET',
      url: 'https://api.telegram.org/bot' + $env.TELEGRAM_BOT_TOKEN + '/getFile?file_id=' + encodeURIComponent(inputFileId),
      timeout: 10000
    });
    const filePath = fileRes?.result?.file_path;
    if (filePath) {
      const audioBuf = await $helpers.httpRequest({
        method: 'GET',
        url: 'https://api.telegram.org/file/bot' + $env.TELEGRAM_BOT_TOKEN + '/' + filePath,
        responseType: 'buffer',
        timeout: 15000
      });
      const groqKey = $env.GROQ_API_KEY || $env.LLM_API_KEY;
      if (groqKey && audioBuf) {
        const whisperRes = await $helpers.httpRequest({
          method: 'POST',
          url: 'https://api.groq.com/openai/v1/audio/transcriptions',
          headers: { 'Authorization': 'Bearer ' + groqKey },
          formData: {
            model: 'whisper-large-v3',
            file: { value: audioBuf, options: { filename: 'voice.ogg', contentType: 'audio/ogg' } },
            response_format: 'json'
          },
          timeout: 30000
        });
        if (whisperRes?.text) {
          inputText = whisperRes.text;
          inputType = 'text';
          jarvisLog('info', 'Transcription succeeded', { length: inputText.length });
        }
      }
    }
  } catch (e) {
    console.error('[input-processor] Voice transcription failed:', e.message);
  }
}

if (inputType !== 'text') {
  if (inputType === 'photo') {
    inputText = '[User sent a photo — image analysis not yet supported]';
    inputType = 'text';
  } else if (inputType === 'document') {
    inputText = '[User sent a document — document analysis not yet supported]';
    inputType = 'text';
  } else if (inputType === 'location' && inputLocation) {
    inputText = 'My location is: ' + inputLocation.latitude + ', ' + inputLocation.longitude;
    inputType = 'text';
  } else if (inputType === 'voice') {
    inputText = '[Voice message — transcription unavailable. Set GROQ_API_KEY for Whisper STT.]';
    inputType = 'text';
  } else {
    inputText = '[Unknown input type — please send text]';
    inputType = 'text';
  }
}

return [{ json: { ...input, inputText, inputType, inputProcessed: true } }];
